VALUES
  ('social-worker-moex-00691', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新管理主義的發展趨勢下，3Es成為組織管理所追求的目標，下列敘述何者錯誤？', '["經濟（economy）意味著以最低成本取得適當的質與量的人力或物資", "強調公共服務之分散化，及供給者之間的合作關係", "效能（effectiveness）係指讓組織能符合人們的要求達成所訂的目標", "明確指出績效的標準和測量，並提供誘因與績效連結"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00692', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案規劃初期，在評量需求的同時，往往也需要盤點資源，理由是要顧及後期的方案評估可以 回應下列那一種標準？', '["可行性標準，方案是務實而謹慎的", "適當性標準，方案是符合法規或倫理的", "發展性標準，方案具備預防或支持效果", "精確性標準，評估的技術或方法能夠決定方案的優缺點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00693', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某方案的目標是「提升照顧者的身心健康」，內容為辦理照顧者的紓壓團體和自我照顧課程等，年 度報告裡呈現了上述活動的時數、參加人數等資訊，這是方案評估的那個部分？', '["產出（output）", "成效（outcome）", "成本效益（cost-benefit）", "服務品質（servicequality）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00694', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '檢視該工作應從事之任務、義務與工作特質的一致性，俾能建立與達成對工作的期望，係屬下列 何種概念的內涵？', '["工作分析", "工作設計", "工作聲明", "工作規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00695', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '績效評估是組織評核員工的例行性業務，但績效評估時經常容易發生一些問題。「對部屬評估時， 以部屬的某項較為突出的特質來推論其他項目的表現」係屬下列何種常見的問題？', '["近期效應", "月暈效應", "刻板印象", "寬嚴不一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00696', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織中有不少與工作相關的壓力源，若因「組織過度與繁複的規則所造成的壓力」係屬下列何種 壓力源？', '["任務需求", "角色需求", "物理環境需求", "組織結構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00697', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工向來是社會福利組織重要的人力資源，有關志工管理，下列敘述何者錯誤？', '["志工管理的第一步是擬定志工人力需求計畫，了解機構是否需要志工", "志工係指不用花錢及不需成本的免費人力", "若志工面試時發現志工的期待與機構能提供的內容有落差，應要委婉拒絕或建議他另尋其他較 適合的機構", "組織應依據志工的專長與興趣，安排適合的工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00698', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關風險與危機對於社會福利組織的影響，下列敘述何者錯誤？', '["若未能妥善預防風險或處理危機，可能影響服務使用者的權益", "對於風險的認知和管理的目標，主要在於維繫組織生存，而非避免服務使用者受到傷害", "社會福利組織須控制其所處系統的風險，如威脅組織的內外部因素", "社會福利組織管理可能存在策略、法令、結構、財務等風險類型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00699', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '危機是突然發生的一種情境或事件，威脅到組織或決策單位的價值或目標，且在情況急遽轉變之 前，可供反應的時間相當有限。有關危機的特性，下列敘述何者錯誤？', '["威脅急迫性", "衝突複雜性", "準確預測性", "雙面效果性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00700', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '處理危機事件有諸多須注意事項，下列敘述何者錯誤？', '["不要急於批評與責備任何人或單位", "不要細水長流式的提供訊息", "不要洩露危機之外的資訊", "不要考量服務對象的權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
